import { KHO_PATHS } from '../appPaths';

const WMS_DOCUMENT_VIEW_PATH: Record<string, (id: string) => string> = {
  GoodsReceipt: KHO_PATHS.pnkDetail,
  MaterialIssue: KHO_PATHS.pxkDetail,
  StageReceipt: () => KHO_PATHS.pnkCongDoan,
  StageIssue: () => KHO_PATHS.pxkCongDoan,
  FgReceipt: () => KHO_PATHS.pnkThanhPham,
  FgIssue: () => KHO_PATHS.pxkThanhPham,
  OutsourceReceipt: () => KHO_PATHS.pnkGiaCong,
  OutsourceIssue: () => KHO_PATHS.pxkGiaCong,
};

export function resolveWmsDocumentViewPath(
  documentType: string | null | undefined,
  documentId: string | null | undefined,
): string | null {
  if (!documentType || !documentId) return null;
  const build = WMS_DOCUMENT_VIEW_PATH[documentType];
  return build ? build(documentId) : null;
}

export function wmsDocumentTypeLabel(documentType: string | null | undefined): string {
  switch (documentType) {
    case 'GoodsReceipt':
      return 'Phiếu nhập kho';
    case 'MaterialIssue':
      return 'Phiếu xuất kho';
    case 'StageReceipt':
      return 'PNK công đoạn';
    case 'StageIssue':
      return 'PXK công đoạn';
    case 'FgReceipt':
      return 'PNK thành phẩm';
    case 'FgIssue':
      return 'PXK thành phẩm';
    case 'OutsourceReceipt':
      return 'PNK gia công';
    case 'OutsourceIssue':
      return 'PXK gia công';
    default:
      return documentType ?? '—';
  }
}
